        // If the popcount is 1, we've already processed it
        if (popcount === 1) continue;

        // Compute next number in the sequence
        const nextNum = popcount;
        if (!dp.has(nextNum)) {
            dp.set(nextNum, count + 1);
            queue.push(nextNum);
        }
    }

    // Count numbers with popcount-depth exactly k
    let result = 0;
    for (let i = 1; i <= n; i++) {
        if (dp.has(i) && dp.get(i) === k) {
            result++;
